import React, { useEffect } from "react";
import { useState } from "react";
import itinerariesActions from "../redux/actions/itinerariesActions";
import { useDispatch, useSelector } from "react-redux"
import { useParams } from "react-router-dom";
import FavoriteBorderIcon from '@mui/icons-material/FavoriteBorder';
import FavoriteIcon from '@mui/icons-material/Favorite';


let emoji = "💵"

function Itineraries(){

    const [likes, setLikes] = useState()
    // console.log(likes)
    const {id}= useParams()

    const dispatch = useDispatch()

    useEffect(()=>{
        dispatch(itinerariesActions.findTinFromCity(id))
    },[])
    
    const itinerary = useSelector(store=>store.itinerariesReducers.itinerary)
    const user = useSelector(store => store.userReducers.user)

    // console.log(itinerary)

    async function likeDislike() {
        const like = await dispatch(itinerariesActions.like(itinerary._id))
        // console.log(like)
        setLikes(like)
    }

    return(
            <div className="itineraries-container">
                {itinerary.length > 0 ?
                    itinerary.map(itinerary=>(
                    <div className="itinerary">
                        <div className="userimage-container">
                            <img src={itinerary.userimage} className="userimage" alt="userimage" />
                            <p>{itinerary.username}</p>
                        </div>
                        <div className="itinerary-body">
                            <h1 className="itinerary-title">{itinerary.itineraryname}</h1>
                            <p>{emoji.repeat(itinerary.price)}</p>
                            <p>{itinerary.hashtags}</p>
                            <p>{itinerary.time}</p>

                            <div>
                                {user ? 
                                (<button onClick={likeDislike}>
                                    {itinerary.likes?.includes(user.id) ? <span><FavoriteBorderIcon/></span> : <span><FavoriteIcon/></span>}
                                </button>) : <span><FavoriteBorderIcon/></span>}
                                <p>{itinerary.likes?.length}</p>
                            </div>

                        </div>
                    </div>
                )) : <h1 className="error-tineraries">There are no itineraries here! come back later.</h1>}
            </div>
    )
    console.log(likeDislike);
}
export default Itineraries
